settings.custom_liquid:
{%- assign has_badges = false -%}
                {%- for b in section.blocks -%}
                  {%- if b.type == 'badge' and b.settings.text != blank -%}
                    {%- assign has_badges = true -%}
                    {%- break -%}
                  {%- endif -%}
                {%- endfor -%}

                {%- if has_badges -%}
                  <div class="product-badges">
                    {%- for b in section.blocks -%}
                      {%- if b.type == 'badge' and b.settings.text != blank -%}
                        <span class="badge" {{ b.shopify_attributes }}>
                          {{ b.settings.text | newline_to_br }}
                        </span>
                      {%- endif -%}
                    {%- endfor -%}
                  </div>
                {%- endif -%}
